            val = 1;
        } else if (c == 'D' || c == 'G') {
            val = 2;
        } else if (c == 'B' || c == 'C' || c == 'M' || c == 'P') {
            val = 3;
        } else if (c == 'F' || c == 'H' || c == 'V' || c == 'W' || c == 'Y') {
            val = 4;
        } else if (c == 'K') {
            val = 5;
        } else if (c == 'J' || c == 'X') {
            val = 8;
        } else if (c == 'Q' || c == 'Z') {
            val = 10;
        } else {
            val = 0;
        }
        total += val;
    }
    total
}

